type AppIconProps = {
	icon: LucideIcon;
} & Omit<React.SVGProps<SVGSVGElement>, "ref"> & {
		strokeWidth?: number;
		size?: number;
	};

export const AppIcon = ({ icon: Icon, size, strokeWidth = 1.5, ...props }: AppIconProps) => (
	<Icon size={size} strokeWidth={strokeWidth} {...props} />
);

// const strokeWidth = "1.5";

